import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import AOS from 'aos';
import 'aos/dist/aos.css';
import { useAuthContext } from '../hooks/useAuthContext';
import {getSpotifyUserId} from '../../apiCalls';
import Logins from '../Logins/Logins';
import SpotifyContext from '../../SpotifyContext';

import './Profile.css';

function Profile({ user }) {
  const { dispatch } = useAuthContext();
  const navigate = useNavigate();
  const [tokenSpotify, setTokenSpotify] = useState();
  const [spotifyUserId, setSpotifyUserId] = useState();
  if(tokenSpotify && !spotifyUserId) {
    getSpotifyUserId(tokenSpotify).then(user => setSpotifyUserId(user.id));
  };

  useEffect(() => {
    AOS.init({
      duration: 800,
      once: true
    });
  }, []);

  if (!user) {
    return (
      <div className="profile-container auth-prompt" data-aos="fade-up">
        <h2 className="profile-title">Welcome</h2>

        <p>
          Please log in or create an account to view your profile and download playlists.
        </p>

        <div className="auth-buttons">
          <Link to="/profile/login" className="spotify-btn login-btn">
            LogIn
          </Link>

          <Link to="/profile/signup" className="spotify-btn signup-btn">
            SignUp
          </Link>
        </div>
      </div>
    );
  }

  function handleLogout() {
    localStorage.removeItem('user'); // clear local storage FIRST
    dispatch({ type: 'LOGOUT' }); // update auth context
    navigate('/profile/login'); // redirect user
  }

  return (
    <div className="profile-container" data-aos="fade-up">
      <h2 className="profile-title">
        {user?.email?.split('@')[0]}'s Profile
      </h2>

      <SpotifyContext.Provider value={{ tokenSpotify, spotifyUserId }}>
        <div className="spotify-section">
          <Logins
            token={tokenSpotify}
            setTokenSpotify={setTokenSpotify}
          />
        </div>
      </SpotifyContext.Provider>

      <button
        className="logout"
        onClick={handleLogout}
      >
        Logout
      </button>

      <ul className="profile-list">
        <li className="profile-list-item">
          <Link className="resetpwd" to="/resetpassword">
            Reset Password
          </Link>
        </li>
      </ul>

    </div>
  );
}

export default Profile;
