import React, { useState } from 'react';
import iconSearch from '../../images/SearchIcon.png';
import './Header.css';
import Movies from '../Movies/movies';
import { useNavigate, Link } from 'react-router-dom';

function Header({ user, handleClick }) {
  const [searching, setSearching] = useState('');
  const [triggerSearch, setTriggerSearch] = useState(0);
  const [hasSearched, setHasSearched] = useState(false);

  const navigate = useNavigate();

  const submittingSearch = (e) => {
    e.preventDefault();

    if (searching.trim() === '') {
      setHasSearched(false);
      return;
    }

    setHasSearched(true);
    setTriggerSearch(prev => prev + 1);
  };

  return (
    <>
      <div className="spotifyHeader">

        <div className="Home">
          <div className="navItem" onClick={() => navigate("/")}>
            Home
          </div>
        </div>

        <div className="centerSection">
          <form onSubmit={submittingSearch} className="searchForm">
            <div className="searchWrapper">
              <img
                src={iconSearch}
                alt="search"
                className="searchIcon"
                onClick={submittingSearch}
              />

              <input
                className="headerSearch"
                type="text"
                placeholder="Search"
                value={searching}
                onChange={(e) => setSearching(e.target.value)}
              />
            </div>
          </form>
        </div>

        <div className="rightSection">
          <div className="navItem" onClick={() => navigate("/help")}>
            Help
          </div>

          <Link className="profile_link" to="/profile">
            <i className="ri-account-circle-fill"></i>
            {user ? user.email.split('@')[0].toUpperCase() : 'Profile'}
          </Link>

          {user && (
            <button onClick={handleClick}>
              Log out
            </button>
          )}
        </div>
      </div>

      {/* SEARCH AREA */}
      {searching.trim() === '' && !hasSearched}

      {triggerSearch !== 0 && searching.trim() !== '' && (
        <Movies searching={searching} triggerSearch={triggerSearch} />
      )}
    </>
  );
}

export default Header;